import{_ as s,o as a,c as e,aw as n}from"./chunks/framework.Dq2onT5h.js";const o=JSON.parse('{"title":"How to create a genesis for your chain","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"How to create a genesis for your chain | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"guides/create-genesis.md","filePath":"guides/create-genesis.md","lastUpdated":1772137846000}');const t=s({name:"guides/create-genesis.md"},[["render",function(s,o,t,l,i,p){return a(),e("div",null,[...o[0]||(o[0]=[n('<h1 id="how-to-create-a-genesis-for-your-chain" tabindex="-1">How to create a genesis for your chain <a class="header-anchor" href="#how-to-create-a-genesis-for-your-chain" aria-label="Permalink to &quot;How to create a genesis for your chain&quot;">​</a></h1><p>This guide will walk you through the process of setting up a genesis for your chain. Follow the steps below to initialize your chain, add a genesis account, and start the chain.</p><h2 id="pre-requisities" tabindex="-1">Pre-requisities <a class="header-anchor" href="#pre-requisities" aria-label="Permalink to &quot;Pre-requisities&quot;">​</a></h2><p>For this guide you need to have a chain directory where you have created and built your chain.</p><p>If you don&#39;t have a chain directory yet, you can initialize a simple ignite chain by following <a href="./gm-world">this tutorial</a></p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>This guide will use the simple ignite chain created in linked guide. Make sure to update any relevant variables to match your chain.</p></div><h2 id="_1-setting-variables" tabindex="-1">1. Setting variables <a class="header-anchor" href="#_1-setting-variables" aria-label="Permalink to &quot;1. Setting variables&quot;">​</a></h2><p>First, set the necessary variables for your chain in the terminal, here is an example:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#DBD7CA;">VALIDATOR_NAME</span><span style="color:#767676;">=</span><span style="color:#BFF3C2;">validator1</span></span>\n<span class="line"><span style="color:#DBD7CA;">CHAIN_ID</span><span style="color:#767676;">=</span><span style="color:#BFF3C2;">gm</span></span>\n<span class="line"><span style="color:#DBD7CA;">KEY_NAME</span><span style="color:#767676;">=</span><span style="color:#BFF3C2;">chain-key</span></span>\n<span class="line"><span style="color:#DBD7CA;">CHAINFLAG</span><span style="color:#767676;">=</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C2;">--chain-id </span><span style="color:#767676;">${</span><span style="color:#BFF3C2;">CHAIN_ID</span><span style="color:#767676;">}</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#DBD7CA;">TOKEN_AMOUNT</span><span style="color:#767676;">=</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C2;">10000000000000000000000000stake</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#DBD7CA;">STAKING_AMOUNT</span><span style="color:#767676;">=</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C2;">1000000000stake</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><h2 id="rebuild-your-chain" tabindex="-1">Rebuild your chain <a class="header-anchor" href="#rebuild-your-chain" aria-label="Permalink to &quot;Rebuild your chain&quot;">​</a></h2><p>Ensure that <code>.gm</code> folder is present at <code>/Users/you/.gm</code> (if not, follow a <a href="./gm-world">Guide</a> to set it up) and run the following command to (re)generate an entrypoint binary out of the code:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">just</span><span style="color:#BFF3C2;"> install</span></span></code></pre></div><p>Once completed, run the following command to ensure that the <code>/Users/you/.gm</code> directory is present:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">ignite</span><span style="color:#BFF3C2;"> evolve</span><span style="color:#BFF3C2;"> init</span></span></code></pre></div><p>This (re)creates an <code>gmd</code> binary that will be used for the rest of the tutorials to run all the operations on the chain.</p><h2 id="resetting-existing-genesis-chain-data" tabindex="-1">Resetting existing genesis/chain data <a class="header-anchor" href="#resetting-existing-genesis-chain-data" aria-label="Permalink to &quot;Resetting existing genesis/chain data&quot;">​</a></h2><p>Reset any existing chain data:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">gmd</span><span style="color:#BFF3C2;"> comet</span><span style="color:#BFF3C2;"> unsafe-reset-all</span></span></code></pre></div><p>Reset any existing genesis data:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">rm</span><span style="color:#FFECB6;"> -rf</span><span style="color:#DBD7CA;"> $HOME</span><span style="color:#BFF3C2;">/.</span><span style="color:#DBD7CA;">$CHAIN_ID</span><span style="color:#BFF3C2;">/config/gentx</span></span>\n<span class="line"><span style="color:#94EEFF;">rm</span><span style="color:#DBD7CA;"> $HOME</span><span style="color:#BFF3C2;">/.</span><span style="color:#DBD7CA;">$CHAIN_ID</span><span style="color:#BFF3C2;">/config/genesis.json</span></span></code></pre></div><h2 id="initializing-the-validator" tabindex="-1">Initializing the validator <a class="header-anchor" href="#initializing-the-validator" aria-label="Permalink to &quot;Initializing the validator&quot;">​</a></h2><p>Initialize the validator with the chain ID you set:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">gmd</span><span style="color:#BFF3C2;"> init</span><span style="color:#DBD7CA;"> $VALIDATOR_NAME </span><span style="color:#FFECB6;">--chain-id</span><span style="color:#DBD7CA;"> $CHAIN_ID</span></span></code></pre></div><h2 id="adding-a-key-to-keyring-backend" tabindex="-1">Adding a key to keyring backend <a class="header-anchor" href="#adding-a-key-to-keyring-backend" aria-label="Permalink to &quot;Adding a key to keyring backend&quot;">​</a></h2><p>Add a key to the keyring-backend:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">gmd</span><span style="color:#BFF3C2;"> keys</span><span style="color:#BFF3C2;"> add</span><span style="color:#DBD7CA;"> $KEY_NAME </span><span style="color:#FFECB6;">--keyring-backend</span><span style="color:#BFF3C2;"> test</span></span></code></pre></div><h2 id="adding-a-genesis-account" tabindex="-1">Adding a genesis account <a class="header-anchor" href="#adding-a-genesis-account" aria-label="Permalink to &quot;Adding a genesis account&quot;">​</a></h2><p>Add a genesis account with the specified token amount:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">gmd</span><span style="color:#BFF3C2;"> genesis</span><span style="color:#BFF3C2;"> add-genesis-account</span><span style="color:#DBD7CA;"> $KEY_NAME $TOKEN_AMOUNT </span><span style="color:#FFECB6;">--keyring-backend</span><span style="color:#BFF3C2;"> test</span></span></code></pre></div><h2 id="setting-the-staking-amount-in-the-genesis-transaction" tabindex="-1">Setting the staking amount in the genesis transaction <a class="header-anchor" href="#setting-the-staking-amount-in-the-genesis-transaction" aria-label="Permalink to &quot;Setting the staking amount in the genesis transaction&quot;">​</a></h2><p>Set the staking amount in the genesis transaction:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">gmd</span><span style="color:#BFF3C2;"> genesis</span><span style="color:#BFF3C2;"> gentx</span><span style="color:#DBD7CA;"> $KEY_NAME $STAKING_AMOUNT </span><span style="color:#FFECB6;">--chain-id</span><span style="color:#DBD7CA;"> $CHAIN_ID </span><span style="color:#FFECB6;">--keyring-backend</span><span style="color:#BFF3C2;"> test</span></span></code></pre></div><h2 id="collecting-genesis-transactions" tabindex="-1">Collecting genesis transactions <a class="header-anchor" href="#collecting-genesis-transactions" aria-label="Permalink to &quot;Collecting genesis transactions&quot;">​</a></h2><p>Collect the genesis transactions:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">gmd</span><span style="color:#BFF3C2;"> genesis</span><span style="color:#BFF3C2;"> collect-gentxs</span></span></code></pre></div><h2 id="configuring-the-genesis-file" tabindex="-1">Configuring the genesis file <a class="header-anchor" href="#configuring-the-genesis-file" aria-label="Permalink to &quot;Configuring the genesis file&quot;">​</a></h2><p>Copy the centralized sequencer address into <code>genesis.json</code>:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#DBD7CA;">ADDRESS</span><span style="color:#767676;">=$(</span><span style="color:#94EEFF;">jq</span><span style="color:#FFECB6;"> -r</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">.address</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#BFF3C2;"> ~/.</span><span style="color:#DBD7CA;">$CHAIN_ID</span><span style="color:#BFF3C2;">/config/priv_validator_key.json</span><span style="color:#767676;">)</span></span>\n<span class="line"><span style="color:#DBD7CA;">PUB_KEY</span><span style="color:#767676;">=$(</span><span style="color:#94EEFF;">jq</span><span style="color:#FFECB6;"> -r</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">.pub_key</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#BFF3C2;"> ~/.</span><span style="color:#DBD7CA;">$CHAIN_ID</span><span style="color:#BFF3C2;">/config/priv_validator_key.json</span><span style="color:#767676;">)</span></span>\n<span class="line"><span style="color:#94EEFF;">jq</span><span style="color:#FFECB6;"> --argjson</span><span style="color:#BFF3C2;"> pubKey</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">$PUB_KEY</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">.consensus[&quot;validators&quot;]=[{&quot;address&quot;: &quot;</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#DBD7CA;">$ADDRESS</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#BFF3C2;">&quot;, &quot;pub_key&quot;: $pubKey, &quot;power&quot;: &quot;1000&quot;, &quot;name&quot;: &quot;Evolve Sequencer&quot;}]</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#BFF3C2;"> ~/.</span><span style="color:#DBD7CA;">$CHAIN_ID</span><span style="color:#BFF3C2;">/config/genesis.json</span><span style="color:#888888;"> &gt;</span><span style="color:#BFF3C2;"> temp.json</span><span style="color:#767676;"> &amp;&amp;</span><span style="color:#94EEFF;"> mv</span><span style="color:#BFF3C2;"> temp.json</span><span style="color:#BFF3C2;"> ~/.</span><span style="color:#DBD7CA;">$CHAIN_ID</span><span style="color:#BFF3C2;">/config/genesis.json</span></span></code></pre></div><h2 id="starting-the-chain" tabindex="-1">Starting the chain <a class="header-anchor" href="#starting-the-chain" aria-label="Permalink to &quot;Starting the chain&quot;">​</a></h2><p>Finally, start the chain with your start command.</p><p>For example, start the simple ignite chain with the following command:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">gmd</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> --evnode.node.aggregator</span></span></code></pre></div><h2 id="share-the-genesis-file" tabindex="-1">Share the genesis file <a class="header-anchor" href="#share-the-genesis-file" aria-label="Permalink to &quot;Share the genesis file&quot;">​</a></h2><p>Once the sequencer is running, share the genesis file with your peers. You can find the genesis file at <code>~/.${CHAIN_ID}/config/genesis.json</code>. Before doing so, add a <code>da_start_height</code> field to the genesis file, that corresponds to the height at which the first height was included on the DA layer. This height can be fetched directly from the <a href="https://github.com/evstack/ev-node/blob/v1.0.0-beta.5/proto/evnode/v1/state_rpc.proto" target="_blank" rel="noreferrer">sequencer RPC</a>.</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">jq</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">.da_start_height = 1</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#BFF3C2;"> ~/.</span><span style="color:#DBD7CA;">$CHAIN_ID</span><span style="color:#BFF3C2;">/config/genesis.json</span><span style="color:#888888;"> &gt;</span><span style="color:#BFF3C2;"> temp.json</span><span style="color:#767676;"> &amp;&amp;</span><span style="color:#94EEFF;"> mv</span><span style="color:#BFF3C2;"> temp.json</span><span style="color:#BFF3C2;"> ~/.</span><span style="color:#DBD7CA;">$CHAIN_ID</span><span style="color:#BFF3C2;">/config/genesis.json</span></span></code></pre></div><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>By following these steps, you will set up the genesis for your chain, initialize the validator, add a genesis account, and start the chain. This guide provides a basic framework for configuring and starting your chain using the gm-world binary. Make sure you initialized your chain correctly, and use the <code>gmd</code> command for all operations.</p>',47)])])}]]);export{o as __pageData,t as default};
